const cfg = $json;
if (!cfg || cfg.interval_days <= 0) {
  console.log('[lembretes] Desativado (interval_days=0)');
  return [];
}
if (cfg.current_hour !== cfg.send_hour) {
  console.log(`[lembretes] Fora da janela — hora atual: ${cfg.current_hour}, configurada: ${cfg.send_hour}`);
  return [];
}
return [{ json: cfg }];

const rows = $input.all();
console.log(`[lembretes] ${rows.length} cliente(s) para lembrete hoje`);
if (!rows || rows.length === 0) return [];
return rows;

const { phone, name, items, total, days_ago } = $json;
const cfg = $('Checar Janela de Envio').first().json;

// Pega o primeiro item do último pedido como referência
const itemList = Array.isArray(items) ? items : [];
const topItem = itemList.length > 0
  ? itemList.sort((a, b) => b.qty - a.qty)[0].name
  : 'seu pedido';

const firstName = name.split(' ')[0];
const template = cfg.msg_template ||
  'Olá, {name}! 😊 Faz {days} dias que você pediu {last_item}. Que saudade! Bora repetir? Digite *2* para pedir 🛒';

const msg = template
  .replace('{name}', firstName)
  .replace('{days}', days_ago)
  .replace('{last_item}', topItem)
  .replace('{establishment}', cfg.establishment_name || '');

return [{ json: { phone, msg } }];

const { phone, msg } = $json;
const instancia = $env['EVOLUTION_INSTANCE'] || 'default';
const apiKey = $env['EVOLUTION_API_KEY'] || '';
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `http://evolution_api:8080/message/sendText/${instancia}`,
    headers: { 'Content-Type': 'application/json', 'apikey': apiKey },
    body: JSON.stringify({ number: phone, text: msg })
  });
} catch(e) { /* non-critical */ }
return [{ json: { phone, ok: true } }];
